package main

import (
	"fmt"
	"sync"
)

// Counters keeps a per-key tally. Multiple goroutines call Inc concurrently.
type Counters struct {
	data map[string]int
}

func NewCounters() *Counters {
	return &Counters{data: make(map[string]int)}
}

func (c *Counters) Inc(key string) {
	c.data[key]++
}

func (c *Counters) Get(key string) int {
	return c.data[key]
}

func main() {
	c := NewCounters()
	var wg sync.WaitGroup
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			key := fmt.Sprintf("k%d", i%5)
			for j := 0; j < 1000; j++ {
				c.Inc(key)
			}
		}(i)
	}
	wg.Wait()
	for i := 0; i < 5; i++ {
		fmt.Printf("k%d -> %d\n", i, c.Get(fmt.Sprintf("k%d", i)))
	}
}
